#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 50005
#define MAXM 500005

int n, Q;
int a[MAXN], b[MAXN];
int k[MAXM], r[MAXM];
int dist[MAXN];
int visited[MAXN];

void bfs(int start, int radius) {
    memset(visited, 0, sizeof(visited));
    visited[start] = 1;
    dist[start] = 0;
    int queue[MAXN], front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (int i = 0; i < n - 1; i++) {
            if (a[i] == u && !visited[b[i]]) {
                visited[b[i]] = 1;
                dist[b[i]] = dist[u] + 1;
                if (dist[b[i]] <= radius) {
                    queue[rear++] = b[i];
                }
            } else if (b[i] == u && !visited[a[i]]) {
                visited[a[i]] = 1;
                dist[a[i]] = dist[u] + 1;
                if (dist[a[i]] <= radius) {
                    queue[rear++] = a[i];
                }
            }
        }
    }
}

int main() {
    scanf("%d", &n);
    for (int i = 0; i < n - 1; i++) {
        scanf("%d %d", &a[i], &b[i]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        scanf("%d", &k[i]);
        for (int j = 0; j < k[i]; j++) {
            scanf("%d %d", &a[j], &r[j]);
        }
    }
    for (int i = 0; i < Q; i++) {
        int count = 0;
        memset(dist, -1, sizeof(dist));
        for (int j = 0; j < k[i]; j++) {
            bfs(a[j], r[j]);
        }
        for (int j = 1; j <= n; j++) {
            if (dist[j] != -1) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

