import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    static final int MAXN = 50005;
    static final int MAXM = 500005;
    static int n, Q;
    static int[] a = new int[MAXN];
    static int[] b = new int[MAXN];
    static int[] k = new int[MAXM];
    static int[] r = new int[MAXM];
    static int[] dist = new int[MAXN];
    static boolean[] visited = new boolean[MAXN];
    static int[][] adj = new int[MAXN][MAXN];
    static int[] cnt = new int[MAXN];

    public static void bfs(int start, int radius) {
        Queue<Integer> q = new LinkedList<>();
        q.add(start);
        visited[start] = true;
        dist[start] = 0;
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int i = 1; i <= n; i++) {
                if (adj[u][i] == 1 && !visited[i]) {
                    visited[i] = true;
                    dist[i] = dist[u] + 1;
                    if (dist[i] <= radius) {
                        q.add(i);
                    }
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        for (int i = 1; i < n; i++) {
            a[i] = sc.nextInt();
            b[i] = sc.nextInt();
            adj[a[i]][b[i]] = 1;
            adj[b[i]][a[i]] = 1;
        }
        Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            k[i] = sc.nextInt();
            for (int j = 0; j < k[i]; j++) {
                a[j] = sc.nextInt();
                r[j] = sc.nextInt();
            }
        }
        for (int i = 0; i < Q; i++) {
            int count = 0;
            for (int j = 1; j <= n; j++) {
                dist[j] = -1;
                visited[j] = false;
            }
            for (int j = 0; j < k[i]; j++) {
                bfs(a[j], r[j]);
            }
            for (int j = 1; j <= n; j++) {
                if (dist[j] != -1) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

